) where
    S: WorkerEventSink,
{
    for progress in progress_events {
        if let Err(error) = context.emit_payload(
            WorkerTaskStatus::Progress,
            downgrader_progress_payload(request_id, progress.progress),
        ) {
            tracing::warn!(
                event = "s09-downgrader-progress-handoff-failed",
                request_id,
