                        }
                    }

                    if root.close-blocked: Text {
                        text: root.close-blocked-text;
                        color: #ffd166;
                        font-size: 10px;
                        wrap: word-wrap;
                    }
                }
            }

            if root.plan-visible: GroupBox {
                title: "Plan";
                height: 76px;

                VerticalLayout {
                    padding: 5px;
                    spacing: 4px;
                    alignment: start;

                    Text {
                        text: root.plan-confirmation-text;
                        color: #f3f3f3;
                        font-size: 11px;
                        wrap: word-wrap;
                    }

                    ScrollView {
                        height: 44px;

                        VerticalLayout {
                            spacing: 3px;
                            alignment: start;

                            for row in root.plan-rows: DowngraderPlanRowItem {
                                entry: row;
                            }
                        }
                    }
                }
            }

            GroupBox {
                title: "Log";
                height: root.plan-visible ? 58px : 134px;

                ScrollView {
                    VerticalLayout {
                        padding: 5px;
                        spacing: 2px;
                        alignment: start;

                        if root.log-rows.length == 0: DowngraderLogRowItem {
                            entry: { level: "info", message: root.log-text };
                        }

                        for row in root.log-rows: DowngraderLogRowItem {
                            entry: row;
                        }
                    }
                }
            }

            HorizontalLayout {
                spacing: 8px;
                alignment: start;

                DowngraderProgressBar {
                    percent: root.progress-percent;
                }

                Text {
                    text: root.progress-text;
                    color: #a8a8a8;
                    font-size: 11px;
                    width: 138px;
                    vertical-alignment: center;
                }
            }
        }
    }
}

