//! Filesystem-backed settings store for reference-compatible CMT settings IO.

use std::{
    fs, io,
    path::{Path, PathBuf},
};

use crate::domain::settings::{AppSettings, RepairDiagnostic, SettingsParseError, UpdateSource};

const SETTINGS_FILE_NAME: &str = "settings.json";
const DOWNLOAD_SOURCE_FILE_NAME: &str = "download-source.txt";

/// Resolves auxiliary settings assets such as `download-source.txt`.
///
/// The abstraction keeps packaged asset lookup separate from settings file IO so
/// tests can inject paths and later packaging can mirror CMT's asset directory
/// behavior without coupling assets to `settings.json` placement.
pub trait AssetResolver {
    /// Reads the configured download source text if the asset is available.
    ///
    /// Returning `Ok(None)` represents a missing asset and causes the settings
    /// store to use the reference-compatible Nexus fallback.
    fn read_download_source(&self) -> io::Result<Option<String>>;
}

/// Filesystem asset resolver rooted at a specific `download-source.txt` path.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FileAssetResolver {
    download_source_path: PathBuf,
}

impl FileAssetResolver {
    /// Creates a resolver for an explicit `download-source.txt` path.
    pub fn new(download_source_path: PathBuf) -> Self {
        Self {
            download_source_path,
        }
    }

    /// Creates the production resolver for `assets/download-source.txt`.
    ///
    /// This mirrors `CMT/src/utils.py::get_asset_path` for non-PyInstaller runs:
    /// assets are resolved under the current directory's `assets` folder, not
    /// beside `settings.json`.
    pub fn production() -> Self {
        Self::new(PathBuf::from("assets").join(DOWNLOAD_SOURCE_FILE_NAME))
    }
}

impl AssetResolver for FileAssetResolver {
    fn read_download_source(&self) -> io::Result<Option<String>> {
        match fs::read_to_string(&self.download_source_path) {
            Ok(source) => Ok(Some(source.trim().to_owned())),
            Err(error) if error.kind() == io::ErrorKind::NotFound => Ok(None),
            Err(error) => Err(error),
        }
    }
}

/// Test and controller helper that returns a fixed asset value.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StaticAssetResolver {
    download_source: Option<String>,
}

impl StaticAssetResolver {
    /// Creates a resolver that returns the provided download source text.
    pub fn new(download_source: Option<&str>) -> Self {
        Self {
            download_source: download_source.map(str::to_owned),
        }
    }
}

impl AssetResolver for StaticAssetResolver {
    fn read_download_source(&self) -> io::Result<Option<String>> {
        Ok(self.download_source.clone())
    }
}

/// Settings and asset paths used by [`SettingsStore`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsPaths<R = FileAssetResolver> {
    settings_path: PathBuf,
    asset_resolver: R,
}

impl SettingsPaths<FileAssetResolver> {
    /// Creates production paths using current-directory `settings.json`.
    pub fn production() -> Self {
        Self {
            settings_path: PathBuf::from(SETTINGS_FILE_NAME),
            asset_resolver: FileAssetResolver::production(),
        }
    }
}

impl<R: AssetResolver> SettingsPaths<R> {
    /// Creates injectable paths for tests or controller-owned settings files.
    pub fn injected(settings_path: PathBuf, asset_resolver: R) -> Self {
        Self {
            settings_path,
            asset_resolver,
        }
    }

    /// Returns the settings JSON path used by the store.
    pub fn settings_path(&self) -> PathBuf {
        self.settings_path.clone()
    }
}

/// Filesystem-backed load/save boundary for [`crate::domain::settings::AppSettings`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SettingsStore<R = FileAssetResolver> {
    paths: SettingsPaths<R>,
}

/// Result returned by [`SettingsStore::load`] after any reference-style repair.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LoadedSettings {
    /// Settings ready for UI/controller use.
    pub settings: AppSettings,
    /// Non-sensitive repair diagnostics collected while loading.
    pub diagnostics: Vec<RepairDiagnostic>,
    /// True when the file was missing, malformed, unreadable, or non-object JSON.
    pub reset_to_defaults: bool,
}

impl SettingsStore<FileAssetResolver> {
    /// Creates a store with production current-directory settings and asset paths.
    pub fn production() -> Self {
        Self::new(SettingsPaths::production())
    }
}

impl<R: AssetResolver> SettingsStore<R> {
    /// Creates a store from explicit settings paths.
    pub fn new(paths: SettingsPaths<R>) -> Self {
        Self { paths }
    }

    /// Creates a store from a settings path and asset resolver.
    pub fn with_asset_resolver(settings_path: PathBuf, asset_resolver: R) -> Self {
        Self::new(SettingsPaths::injected(settings_path, asset_resolver))
    }

    /// Returns the settings file path without touching the filesystem.
    pub fn settings_path(&self) -> &Path {
        &self.paths.settings_path
    }

    /// Resolves the default update source through `download-source.txt`.
    ///
    /// Missing, unreadable, or invalid content falls back to Nexus so a damaged
    /// packaged asset never prevents startup.
    pub fn default_update_source(&self) -> UpdateSource {
        self.paths
            .asset_resolver
            .read_download_source()
            .ok()
            .flatten()
            .as_deref()
            .and_then(UpdateSource::from_wire_value)
            .unwrap_or(UpdateSource::Nexus)
    }

    /// Loads settings, creating or repairing `settings.json` as needed.
    ///
    /// Missing files and malformed/non-object JSON reset to default settings and
    /// are saved immediately, matching the reference app's quiet first-run and
    /// recovery behavior. Syntactically valid objects preserve valid keys, repair
    /// invalid values, remove unknown keys on resave, and return diagnostics for
    /// later logging without surfacing UI errors.
    pub fn load(&self) -> io::Result<LoadedSettings> {
        let defaults = AppSettings {
            update_source: self.default_update_source(),
            ..Default::default()
        };

        let source = match fs::read_to_string(&self.paths.settings_path) {
            Ok(source) => source,
            Err(error) if error.kind() == io::ErrorKind::NotFound => {
                self.save(&defaults)?;
                return Ok(LoadedSettings {
                    settings: defaults,
                    diagnostics: Vec::new(),
                    reset_to_defaults: true,
                });
            }
            Err(_) => {
                self.save(&defaults)?;
                return Ok(LoadedSettings {
                    settings: defaults,
                    diagnostics: Vec::new(),
                    reset_to_defaults: true,
                });
            }
        };

        let repaired = match AppSettings::from_json_str(&source) {
            Ok(repaired) => repaired,
            Err(SettingsParseError::MalformedJson(_)) | Err(SettingsParseError::NonObjectRoot) => {
                self.save(&defaults)?;
                return Ok(LoadedSettings {
                    settings: defaults,
                    diagnostics: Vec::new(),
                    reset_to_defaults: true,
                });
            }
        };

        if !repaired.diagnostics.is_empty() {
            self.save(&repaired.settings)?;
        }

        Ok(LoadedSettings {
            settings: repaired.settings,
            diagnostics: repaired.diagnostics,
            reset_to_defaults: false,
        })
    }

    /// Saves settings JSON and returns filesystem errors to the caller.
    ///
    /// The serialized object is produced by the domain model, so unknown keys are
    /// never persisted and later UI/controller code can revert state if this file
    /// write fails.
    pub fn save(&self, settings: &AppSettings) -> io::Result<()> {
        let mut json =
            serde_json::to_string_pretty(&settings.to_json_value()).map_err(io::Error::other)?;
        json.push('\n');
        fs::write(&self.paths.settings_path, json)
    }
}

#[cfg(test)]
mod tests {
    use std::{
        fs,
        path::PathBuf,
        time::{SystemTime, UNIX_EPOCH},
    };

    use crate::domain::settings::{AppSettings, LogLevel, UpdateSource};

    use super::*;

    #[test]
    fn settings_store_uses_current_directory_settings_json_by_default() {
        let paths = SettingsPaths::production();

        assert_eq!(paths.settings_path(), PathBuf::from("settings.json"));
    }

    #[test]
    fn injected_paths_and_asset_resolver_drive_update_source_defaults() {
        let temp_root = std::env::temp_dir().join("cmt-rs-settings-store-red");
        let settings_path = temp_root.join("isolated-settings.json");
        let asset_path = temp_root.join("download-source.txt");

[178 more lines in file. Use offset=261 to continue.]

        assert_eq!(error.user_message(), UNSAFE_MANAGED_PATH_MESSAGE);
    }

    #[derive(Debug, Clone, PartialEq, Eq)]
    enum RecordedWriteOp {
        Write(PathBuf),
        Copy { from: PathBuf, to: PathBuf },
        Rename { from: PathBuf, to: PathBuf },
        Remove(PathBuf),
    }

    #[derive(Debug, Default)]
    struct RecordingWritableFilesystem {
        nodes: RefCell<BTreeMap<PathBuf, FakeNode>>,
        operations: RefCell<Vec<RecordedWriteOp>>,
        failures: RefCell<BTreeMap<(PlatformOperation, PathBuf), PlatformErrorKind>>,
    }

    impl RecordingWritableFilesystem {
        fn with_dir(self, path: impl Into<PathBuf>) -> Self {
            self.nodes
                .borrow_mut()
                .insert(path.into(), FakeNode::Directory);
            self
        }

        fn with_file(self, path: impl Into<PathBuf>, bytes: impl Into<Vec<u8>>) -> Self {
            let path = path.into();
            self.ensure_parent_dirs(&path);
            self.nodes
                .borrow_mut()
                .insert(path, FakeNode::File(bytes.into()));
            self
        }

        fn with_crc_file(self, path: impl Into<PathBuf>, crc32: &str) -> Self {
            self.with_file(path, bytes_with_crc(crc32))
        }

        fn with_failure(
            self,
            operation: PlatformOperation,
            path: impl Into<PathBuf>,
            kind: PlatformErrorKind,
        ) -> Self {
            self.failures
                .borrow_mut()
                .insert((operation, path.into()), kind);
            self
        }

        fn ensure_parent_dirs(&self, path: &Path) {
            let mut parents = Vec::new();
            let mut current = path.parent();
            while let Some(parent) = current {
                if parent.as_os_str().is_empty() {
                    break;
                }
                parents.push(parent.to_path_buf());
                current = parent.parent();
            }
            let mut nodes = self.nodes.borrow_mut();
            for parent in parents.into_iter().rev() {
                nodes.entry(parent).or_insert(FakeNode::Directory);
            }
        }

        fn maybe_fail(
            &self,
            operation: PlatformOperation,
            path: &Path,
        ) -> Result<(), PlatformError> {
            if let Some(kind) = self
                .failures
                .borrow()
                .get(&(operation, path.to_path_buf()))
                .copied()
            {
                return Err(PlatformError::new(
                    operation,
                    path.display().to_string(),
                    kind,
                    format!(
                        "{} target could not be accessed because permission was denied.",
                        operation.label()
                    ),
                ));
            }
            Ok(())
        }

        fn node(
            &self,
            path: &Path,
            operation: PlatformOperation,
        ) -> Result<FakeNode, PlatformError> {
            self.nodes.borrow().get(path).cloned().ok_or_else(|| {
                PlatformError::new(
                    operation,
                    path.display().to_string(),
                    PlatformErrorKind::NotFound,
                    format!("{} target was not found.", operation.label()),
                )
            })
        }

        fn has_file(&self, path: impl AsRef<Path>) -> bool {
            matches!(
                self.nodes.borrow().get(path.as_ref()),
                Some(FakeNode::File(_) | FakeNode::SymlinkFile(_) | FakeNode::ReparseFile(_))
            )
        }

        fn file_crc(&self, path: impl AsRef<Path>) -> Option<String> {
            match self.nodes.borrow().get(path.as_ref()) {
                Some(
                    FakeNode::File(bytes)
                    | FakeNode::SymlinkFile(bytes)
                    | FakeNode::ReparseFile(bytes),
                ) => Some(crc32_hex(bytes)),
                _ => None,
            }
        }

        fn operations(&self) -> Vec<RecordedWriteOp> {
            self.operations.borrow().clone()
        }
    }

    impl Filesystem for RecordingWritableFilesystem {
        fn metadata(&self, path: &Path) -> Result<FileMetadata, PlatformError> {
            self.maybe_fail(PlatformOperation::ReadMetadata, path)?;
            match self.node(path, PlatformOperation::ReadMetadata)? {
                FakeNode::File(bytes) | FakeNode::SymlinkFile(bytes) => {
                    Ok(FileMetadata::new(FileType::File, bytes.len() as u64))
                }
                FakeNode::ReparseFile(bytes) => Ok(FileMetadata::reparse_point(
                    FileType::File,
                    bytes.len() as u64,
                )),
                FakeNode::Directory => Ok(FileMetadata::new(FileType::Directory, 0)),
                FakeNode::UnreadableFile => Ok(FileMetadata::new(FileType::File, 0)),
            }
        }

        fn symlink_metadata(&self, path: &Path) -> Result<FileMetadata, PlatformError> {
            self.maybe_fail(PlatformOperation::ReadMetadata, path)?;
            match self.node(path, PlatformOperation::ReadMetadata)? {
                FakeNode::File(bytes) => Ok(FileMetadata::new(FileType::File, bytes.len() as u64)),
                FakeNode::SymlinkFile(bytes) => {
                    Ok(FileMetadata::new(FileType::Symlink, bytes.len() as u64))
                }
                FakeNode::ReparseFile(bytes) => Ok(FileMetadata::reparse_point(
                    FileType::File,
                    bytes.len() as u64,
                )),
                FakeNode::Directory => Ok(FileMetadata::new(FileType::Directory, 0)),
                FakeNode::UnreadableFile => Ok(FileMetadata::new(FileType::File, 0)),
            }
        }

        fn read_bytes(&self, path: &Path) -> Result<Vec<u8>, PlatformError> {
            self.maybe_fail(PlatformOperation::ReadFile, path)?;
            match self.node(path, PlatformOperation::ReadFile)? {
                FakeNode::File(bytes)
                | FakeNode::SymlinkFile(bytes)
                | FakeNode::ReparseFile(bytes) => Ok(bytes),
                FakeNode::Directory => Err(PlatformError::new(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    PlatformErrorKind::InvalidInput,
                    "File read target is invalid.",
                )),
                FakeNode::UnreadableFile => Err(safe_platform_error(
                    path,
                    PlatformOperation::ReadFile,
                    PlatformErrorKind::PermissionDenied,
                )),
            }
        }

        fn read_to_string(&self, path: &Path) -> Result<String, PlatformError> {
            String::from_utf8(self.read_bytes(path)?).map_err(|error| {
                PlatformError::parse_error(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    error.to_string(),
                )
            })
        }

        fn read_dir(&self, path: &Path) -> Result<Vec<DirectoryEntry>, PlatformError> {
            self.node(path, PlatformOperation::ReadDirectory)?;
            Ok(Vec::new())
        }

        fn walk_dir(&self, path: &Path) -> Result<Vec<DirectoryEntry>, PlatformError> {
            self.node(path, PlatformOperation::WalkDirectory)?;
            Ok(Vec::new())
        }
    }

    impl WritableFilesystem for RecordingWritableFilesystem {
        fn write_bytes(&self, path: &Path, bytes: &[u8]) -> PlatformResult<()> {
            self.maybe_fail(PlatformOperation::WriteFile, path)?;
            self.ensure_parent_dirs(path);
            self.nodes
                .borrow_mut()
                .insert(path.to_path_buf(), FakeNode::File(bytes.to_vec()));
            self.operations
                .borrow_mut()
                .push(RecordedWriteOp::Write(path.to_path_buf()));
            Ok(())
        }

        fn replace_file_bytes(&self, path: &Path, bytes: &[u8]) -> PlatformResult<()> {
            self.maybe_fail(PlatformOperation::WriteFile, path)?;
            if !self.has_file(path) {
                return Err(PlatformError::new(
                    PlatformOperation::WriteFile,
                    path.display().to_string(),
                    PlatformErrorKind::NotFound,
                    "File write target was not found.",
                ));
            }
            self.ensure_parent_dirs(path);
            self.nodes
                .borrow_mut()
                .insert(path.to_path_buf(), FakeNode::File(bytes.to_vec()));
            self.operations
                .borrow_mut()
                .push(RecordedWriteOp::Write(path.to_path_buf()));
            Ok(())
        }

        fn copy_file(&self, from: &Path, to: &Path) -> PlatformResult<()> {
            self.maybe_fail(PlatformOperation::CopyFile, to)?;
            let bytes = match self.node(from, PlatformOperation::CopyFile)? {
                FakeNode::File(bytes) => bytes,
                FakeNode::Directory
                | FakeNode::UnreadableFile
                | FakeNode::SymlinkFile(_)
                | FakeNode::ReparseFile(_) => {
                    return Err(PlatformError::new(
                        PlatformOperation::CopyFile,
                        from.display().to_string(),
                        PlatformErrorKind::InvalidInput,
                        "File copy target is invalid.",
                    ));
                }
            };
            self.ensure_parent_dirs(to);
            self.nodes
                .borrow_mut()
                .insert(to.to_path_buf(), FakeNode::File(bytes));
            self.operations.borrow_mut().push(RecordedWriteOp::Copy {
                from: from.to_path_buf(),
                to: to.to_path_buf(),
            });
            Ok(())
        }

        fn rename_file(&self, from: &Path, to: &Path) -> PlatformResult<()> {
            self.maybe_fail(PlatformOperation::RenameFile, to)?;
            let node = self.node(from, PlatformOperation::RenameFile)?;
            if !matches!(node, FakeNode::File(_)) {
                return Err(PlatformError::new(
                    PlatformOperation::RenameFile,
                    from.display().to_string(),
                    PlatformErrorKind::InvalidInput,
                    "File rename target is invalid.",
                ));
            }
            self.ensure_parent_dirs(to);
            let mut nodes = self.nodes.borrow_mut();
            nodes.remove(from);
            nodes.insert(to.to_path_buf(), node);
            self.operations.borrow_mut().push(RecordedWriteOp::Rename {
                from: from.to_path_buf(),
                to: to.to_path_buf(),
            });
            Ok(())
        }

        fn remove_file(&self, path: &Path) -> PlatformResult<()> {
            self.maybe_fail(PlatformOperation::RemoveFile, path)?;
            match self.nodes.borrow_mut().remove(path) {
                Some(FakeNode::File(_))
                | Some(FakeNode::UnreadableFile)
                | Some(FakeNode::SymlinkFile(_))
                | Some(FakeNode::ReparseFile(_)) => {
                    self.operations
                        .borrow_mut()
                        .push(RecordedWriteOp::Remove(path.to_path_buf()));
                    Ok(())
                }
                Some(FakeNode::Directory) => Err(PlatformError::new(
                    PlatformOperation::RemoveFile,
                    path.display().to_string(),
                    PlatformErrorKind::InvalidInput,
                    "File removal target is invalid.",
                )),
                None => Err(PlatformError::new(
                    PlatformOperation::RemoveFile,
                    path.display().to_string(),
                    PlatformErrorKind::NotFound,
                    "File removal target was not found.",
                )),
            }
        }
    }

    #[derive(Debug)]
    struct RecordingDownloader {
        calls: RefCell<Vec<String>>,
        result: Result<Vec<u8>, DowngraderDownloadError>,
        progress: Vec<f32>,
    }

    impl RecordingDownloader {
        fn ok(bytes: impl Into<Vec<u8>>) -> Self {
            Self {
                calls: RefCell::new(Vec::new()),
                result: Ok(bytes.into()),
                progress: vec![0.0, 50.0, 100.0],
            }
        }

        fn failing() -> Self {
            Self {
                calls: RefCell::new(Vec::new()),
                result: Err(DowngraderDownloadError::request("network unavailable")),
                progress: vec![0.0],
            }
        }

        fn calls(&self) -> Vec<String> {
            self.calls.borrow().clone()
        }
    }

    impl DeltaDownloader for RecordingDownloader {
        fn download_delta(
            &self,
            url: &str,
            progress: &mut dyn FnMut(DowngraderProgress),
        ) -> Result<Vec<u8>, DowngraderDownloadError> {
            self.calls.borrow_mut().push(url.to_owned());
            for percent in &self.progress {
                progress(DowngraderProgress::new(*percent));
            }
            self.result.clone()
        }
    }

    #[derive(Debug)]
    struct RecordingApplier {
        calls: RefCell<Vec<(Vec<u8>, Vec<u8>)>>,
        result: Result<Vec<u8>, DowngraderDeltaApplyError>,
    }

    impl RecordingApplier {
        fn ok(bytes: impl Into<Vec<u8>>) -> Self {
            Self {
                calls: RefCell::new(Vec::new()),
                result: Ok(bytes.into()),
            }
        }

        fn failing() -> Self {
            Self {
                calls: RefCell::new(Vec::new()),
                result: Err(DowngraderDeltaApplyError::failed("malformed patch")),
            }
        }

        fn calls(&self) -> Vec<(Vec<u8>, Vec<u8>)> {
            self.calls.borrow().clone()
        }
    }

    impl DeltaApplier for RecordingApplier {
        fn apply_delta(
            &self,
            source_bytes: &[u8],
            patch_bytes: &[u8],
            _expected_output_bytes: u64,
        ) -> Result<Vec<u8>, DowngraderDeltaApplyError> {
            self.calls
                .borrow_mut()
                .push((source_bytes.to_vec(), patch_bytes.to_vec()));
            self.result.clone()
        }
    }

    fn executor_request(
        request_id: u64,
        keep_backups: bool,
        delete_deltas: bool,
    ) -> DowngraderExecutionRequest<'static> {
        let installation = Box::leak(Box::new(installation()));
        DowngraderExecutionRequest::new(
            request_id,
            Some(installation),
            options(DowngraderTarget::OldGen, keep_backups, delete_deltas),
        )
    }

