                );
                return Err(DowngraderServiceError::ConfirmedPlanChanged {
                    safe_message: CONFIRMED_PLAN_CHANGED_MESSAGE.to_owned(),
                    expected_digest: expected_digest.to_owned(),
                    actual_digest,
                });
            }
        }
