+6324         let mut controller = s09_runtime_ready_controller();
+6325         let plan_request = match controller.request_patch_all() {
+6326             Some(DowngraderPatchWorkerRequest::PreviewPlan(request)) => request,
+6327             other => panic!("expected plan request, got {other:?}"),
+6328         };
+6329         assert_eq!(
+6330             controller.plan_ready(
+6331                 plan_request.request_id,
+6332                 s09_runtime_plan(plan_request.request_id, plan_request.options),
+6333             ),
+6334             DowngraderTransitionResult::Applied
+6335         );
+6336         let run_request = match controller.request_patch_all() {
+6337             Some(DowngraderPatchWorkerRequest::ConfirmedRun(request)) => request,
+6338             other => panic!("expected run request, got {other:?}"),
+6339         };
+6340         assert!(!run_request.confirmed_plan_digest.is_empty());
+6341 
+6342         assert_eq!(controller.request_close(), DowngraderTransitionResult::CloseBlocked);
+6343         assert!(project_downgrader_state(&controller).close_blocked);
+6344         assert_eq!(
+6345             controller.handle_worker_event(WorkerEvent::new(
+6346                 run_request.task.clone(),
+6347                 WorkerTaskStatus::Progress,
+6348                 downgrader_progress_payload(run_request.request_id, DowngraderProgress::new(37.5)),
+6349             )),
+6350             DowngraderTransitionResult::Applied
+6351         );
+6352         assert_eq!(
+6353             controller.handle_worker_event(WorkerEvent::new(
+6354                 run_request.task.clone(),
+6355                 WorkerTaskStatus::Progress,
+6356                 downgrader_log_row_payload(
+6357                     run_request.request_id,
+6358                     DowngraderExecutionLogRow::new(DowngraderLogLevel::Info, "Downloading patch."),
+6359                 ),
+6360             )),
+6361             DowngraderTransitionResult::Applied
+6362         );
+6363         let projection = project_downgrader_state(&controller);
+6364         assert_eq!(projection.progress_percent, 37.5);
+6365         assert!(projection
+6366             .log_rows
+6367             .iter()
+6368             .any(|row| row.message.as_str() == "Downloading patch."));
+6369 
+6370         assert_eq!(
+6371             controller.handle_worker_event(WorkerEvent::completed(
+6372                 app::downgrader_controller::downgrader_run_task(run_request.request_id + 100),
+6373                 downgrader_run_completed_payload(
+6374                     run_request.request_id + 100,
+6375                     s09_runtime_execution_result(run_request.request_id + 100),
+6376                 ),
+6377             )),
