+6385                 run_request.request_id,
+6386                 WorkerSpawnError::NoActiveRuntime {
+6387                     task_id: run_request.task.id.clone(),
+6388                 },
+6389             ),
+6390             DowngraderTransitionResult::Applied
+6391         );
+6392         let projection = project_downgrader_state(&controller);
+6393         assert!(!projection.patch_enabled);
+6394         assert!(!projection.close_blocked);
+6395         assert!(projection.log_text.contains("could not be started"));
